entity MyEntity is
  port (
    clk : in std_logic;
    rst : in std_logic;
    data_out : out std_logic_vector(7 downto 0)
  );
end MyEntity;

architecture Behavioral of MyEntity is
begin
  process(clk, rst)
  begin
    if rst = '1' then
      data_out <= (others => '0');
    elsif rising_edge(clk) then
      -- logic here
    end if;
  end process;
end Behavioral;

module MyModule (
  input wire clk,
  input wire rst,
  output reg [7:0] data_out
);
endmodule

entity tb_MyEntity is
end tb_MyEntity;

architecture sim of tb_MyEntity is
  signal clk : std_logic := '0';
  signal rst : std_logic := '1';
  signal data_out : std_logic_vector(7 downto 0);

  component MyEntity
    port (
      clk : in std_logic;
      rst : in std_logic;
      data_out : out std_logic_vector(7 downto 0)
    );
  end component;

begin
  uut: MyEntity port map (
    clk => clk,
    rst => rst,
    data_out => data_out
  );

  clk <= not clk after 10 ns;

  process
  begin
    rst <= '0' after 20 ns;
    wait;
  end process;
end sim;

module tb_MyModule;
  reg clk;
  reg rst;
  wire [7:0] data_out;

  MyModule uut (
    .clk(clk),
    .rst(rst),
    .data_out(data_out)
  );

  initial begin
    clk = 0;
    rst = 1;
    #20 rst = 0;
  end

  always #10 clk = ~clk;
endmodule
